import random  
import string  

def load_font_style(file_path):  
    try:  
        with open(file_path, 'r') as file:  
            font_style = file.read()  
            return font_style  
    except FileNotFoundError:  
        print("Error: Font style file not found.")  
        return None  
    except Exception:  
        print("Error: Unknown error")  
        return None  

def generate_standard_font(word):  
    art = ""  
    for letter in word:  
        art += letter + "\n"  
    return art  

def generate_bold_font(word):  
    art = ""  
    for letter in word:  
        art += letter.upper() + "\n"  
    return art  

def generate_italic_font(word):  
    art = ""  
    for letter in word:  
        art += "/" + letter + "\n"  
    return art  

def generate_underline_font(word):  
    art = ""  
    for letter in word:  
        art += "_" + letter + "\n"  
    return art  

def generate_ascii_art(word, font_style):  
    art = ""  
    for letter in word:  
        art += font_style(letter)  
    return art  

def main():  
    word = input("Enter a word: ")  
    font_styles = [generate_standard_font, generate_bold_font, generate_italic_font, generate_underline_font]  
    font_style = random.choice(font_styles)  
    ascii_art = generate_ascii_art(word, font_style)  
    print(ascii_art)  

if __name__ == "__main__":  
    main()
